var ECOS_SDD_BY_ID = ECOS_SDD_DATA.reduce(function(acc, sdd) {
    acc[sdd.id] = sdd;
    return acc;
}, {});

var ECOS_SDD_BY_NUMBER = ECOS_SDD_DATA.reduce(function(acc, sdd) {
    acc[String(sdd.number)] = sdd;
    return acc;
}, {});

function getECOSSDDById(id) {
    return ECOS_SDD_BY_ID[id] || null;
}

function getECOSSDDByNumber(number) {
    return ECOS_SDD_BY_NUMBER[String(number)] || ECOS_SDD_BY_ID['SDD-' + String(number).padStart(3, '0')] || null;
}

function getECOSSpecialtyById(id) {
    return ECOS_SPECIALTIES.find(function(s) { return s.id === id; }) || null;
}

function getECOSSDDBySpecialty(specialtyId) {
    return ECOS_SDD_DATA.filter(function(sdd) {
        return Array.isArray(sdd.specialties) && sdd.specialties.indexOf(specialtyId) !== -1;
    });
}

function getECOSSDDByFamily(familyName) {
    return ECOS_SDD_DATA.filter(function(sdd) { return sdd.family === familyName; });
}
